SELECT u.id, u.username, u.real_name, u.phone, u.email, u.status, u.last_login_time, u.create_time, GROUP_CONCAT(r.role_code ORDER BY r.role_code SEPARATOR ',') AS role_codes FROM sys_user u LEFT JOIN sys_user_role ur ON ur.user_id = u.id LEFT JOIN sys_role r ON r.id = ur.role_id AND r.deleted = 0
u.deleted = 0 AND u.status = #{status}
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
AND EXISTS ( SELECT 1 FROM sys_user_role ur2 JOIN sys_role r2 ON r2.id = ur2.role_id WHERE ur2.user_id = u.id AND r2.role_code = #{roleCode} AND r2.deleted = 0 )
GROUP BY u.id, u.username, u.real_name, u.phone, u.email, u.status, u.last_login_time, u.create_time ORDER BY u.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT u.id) FROM sys_user u
JOIN sys_user_role ur2 ON ur2.user_id = u.id JOIN sys_role r2 ON r2.id = ur2.role_id AND r2.deleted = 0
u.deleted = 0 AND u.status = #{status}
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
AND r2.role_code = #{roleCode}
